+/// Knowledge base subcommands
+#[derive(Subcommand, Debug)]
+pub enum KnowledgeCommands {
+    /// Add a new knowledge entry
+    Add {
+        /// Entry type: solution, pattern, prompt, debug_log
+        #[arg(long)]
+        entry_type: String,
+
+        /// Title for the entry
+        #[arg(long)]
+        title: String,
+
+        /// Content (use - for stdin)
+        #[arg(long)]
+        content: String,
+
+        /// Summary (auto-truncated from content if omitted)
+        #[arg(long)]
+        summary: Option<String>,
+
+        /// Source session ID
+        #[arg(long)]
+        session: Option<String>,
+
+        /// Source file path
+        #[arg(long)]
+        file: Option<String>,
+
+        /// Source line range (e.g. "10-25")
+        #[arg(long)]
+        lines: Option<String>,
+
+        /// Tags (comma-separated)
+        #[arg(long)]
+        tags: Option<String>,
+    },
+
+    /// Search knowledge entries
+    Search {
+        /// Search query
+        query: String,
+
+        /// Filter by entry type: solution, pattern, prompt, debug_log
+        #[arg(long)]
+        entry_type: Option<String>,
+
+        /// Filter by tags (comma-separated)
+        #[arg(long)]
+        tags: Option<String>,
+
+        /// Maximum results to return
+        #[arg(long, default_value = "20")]
+        limit: usize,
+    },
+
+    /// Show a specific knowledge entry
+    Show {
+        /// Entry ID
+        id: i64,
+    },
+
+    /// List recent knowledge entries
+    List {
+        /// Maximum entries to return
+        #[arg(long, default_value = "20")]
+        limit: usize,
+
+        /// Filter by entry type
+        #[arg(long)]
+        entry_type: Option<String>,
+    },
+
+    /// Show top-rated entries
+    Top {
+        /// Maximum entries to return
+        #[arg(long, default_value = "10")]
+        limit: usize,
+    },
+
+    /// Add feedback to a knowledge entry
+    Feedback {
+        /// Entry ID
+        id: i64,
+
+        /// Feedback type: helpful, not_helpful, outdated
+        #[arg(long)]
+        feedback_type: String,
+
+        /// Optional comment
+        #[arg(long)]
+        comment: Option<String>,
+
+        /// Session ID for tracking
+        #[arg(long)]
+        session: Option<String>,
+    },
+}
